import scala.util.Random
import java.time.{Instant, Duration}
import java.util.concurrent.ConcurrentHashMap
import scala.collection.concurrent
import scala.jdk.CollectionConverters._

case class SessionToken(
  token: String,
  userId: String,
  createdAt: Instant,
  expiresAt: Instant,
  isActive: Boolean = true
)

case class ApiKey(
  key: String,
  secret: String,
  owner: String,
  createdAt: Instant,
  expiresAt: Option[Instant] = None,
  isActive: Boolean = true,
  scopes: Set[String] = Set.empty
)

trait TokenGenerator {
  def generateToken(length: Int = 32): String
  def generateHexToken(length: Int = 32): String
}

class DefaultTokenGenerator extends TokenGenerator {
  override def generateToken(length: Int = 32): String = {
    Random.alphanumeric.take(length).mkString
  }

  override def generateHexToken(length: Int = 32): String = {
    val bytes = new Array[Byte](length / 2)
    Random.nextBytes(bytes)
    bytes.map("%02x".format(_)).mkString
  }
}

class SessionManager(
  tokenGenerator: TokenGenerator = new DefaultTokenGenerator(),
  sessionDuration: Duration = Duration.ofHours(24),
  maxSessionsPerUser: Int = 5
) {

  private val sessions: concurrent.Map[String, SessionToken] =
    new ConcurrentHashMap[String, SessionToken]().asScala

  private val userSessions: concurrent.Map[String, Set[String]] =
    new ConcurrentHashMap[String, Set[String]]().asScala

  def createSession(userId: String): SessionToken = {
    enforceMaxSessions(userId)

    val token = tokenGenerator.generateToken(32)
    val now = Instant.now()
    val session = SessionToken(
      token = token,
      userId = userId,
      createdAt = now,
      expiresAt = now.plus(sessionDuration)
    )

    sessions.put(token, session)
    userSessions.updateWith(userId) {
      case Some(tokens) => Some(tokens + token)
      case None => Some(Set(token))
    }

    println(s"[SessionManager] Created session for user '$userId': token=${token.take(8)}...")
    session
  }

  def validateSession(token: String): Option[SessionToken] = {
    sessions.get(token).flatMap { session =>
      if (!session.isActive) {
        println(s"[SessionManager] Session is inactive: ${token.take(8)}...")
        None
      } else if (Instant.now().isAfter(session.expiresAt)) {
        println(s"[SessionManager] Session expired: ${token.take(8)}...")
        invalidateSession(token)
        None
      } else {
        Some(session)
      }
    }
  }

  def refreshSession(token: String): Option[SessionToken] = {
    validateSession(token).map { existingSession =>
      val now = Instant.now()
      val refreshedSession = existingSession.copy(
        expiresAt = now.plus(sessionDuration)
      )
      sessions.put(token, refreshedSession)
      println(s"[SessionManager] Refreshed session: ${token.take(8)}...")
      refreshedSession
    }
  }

  def invalidateSession(token: String): Boolean = {
    sessions.remove(token) match {
      case Some(session) =>
        userSessions.updateWith(session.userId) {
          case Some(tokens) =>
            val updated = tokens - token
            if (updated.isEmpty) None else Some(updated)
          case None => None
        }
        println(s"[SessionManager] Invalidated session: ${token.take(8)}...")
        true
      case None => false
    }
  }

  def invalidateAllUserSessions(userId: String): Int = {
    val tokens = userSessions.getOrElse(userId, Set.empty)
    tokens.foreach(sessions.remove)
    userSessions.remove(userId)
    println(s"[SessionManager] Invalidated ${tokens.size} sessions for user '$userId'")
    tokens.size
  }

  def getActiveSessions(userId: String): List[SessionToken] = {
    userSessions.getOrElse(userId, Set.empty)
      .flatMap(sessions.get)
      .filter(s => s.isActive && Instant.now().isBefore(s.expiresAt))
      .toList
  }

  def cleanupExpiredSessions(): Int = {
    val now = Instant.now()
    val expired = sessions.filter { case (_, session) =>
      now.isAfter(session.expiresAt)
    }.keys.toList

    expired.foreach(invalidateSession)
    println(s"[SessionManager] Cleaned up ${expired.size} expired sessions")
    expired.size
  }

  def totalActiveSessions: Int = sessions.size

  private def enforceMaxSessions(userId: String): Unit = {
    val currentSessions = getActiveSessions(userId)
    if (currentSessions.size >= maxSessionsPerUser) {
      val oldest = currentSessions.sortBy(_.createdAt).head
      invalidateSession(oldest.token)
      println(s"[SessionManager] Evicted oldest session for user '$userId' (max sessions reached)")
    }
  }
}

class ApiKeyManager(
  tokenGenerator: TokenGenerator = new DefaultTokenGenerator()
) {

  private val apiKeys: concurrent.Map[String, ApiKey] =
    new ConcurrentHashMap[String, ApiKey]().asScala

  private val ownerKeys: concurrent.Map[String, Set[String]] =
    new ConcurrentHashMap[String, Set[String]]().asScala

  def generateApiKey(
    owner: String,
    scopes: Set[String] = Set("read"),
    expiresIn: Option[Duration] = None
  ): ApiKey = {
    val key = "ak_" + tokenGenerator.generateToken(32)
    val secret = "sk_" + tokenGenerator.generateToken(48)
    val now = Instant.now()

    val apiKey = ApiKey(
      key = key,
      secret = secret,
      owner = owner,
      createdAt = now,
      expiresAt = expiresIn.map(now.plus),
      scopes = scopes
    )

    apiKeys.put(key, apiKey)
    ownerKeys.updateWith(owner) {
      case Some(keys) => Some(keys + key)
      case None => Some(Set(key))
    }

    println(s"[ApiKeyManager] Generated API key for owner '$owner': ${key.take(12)}...")
    apiKey
  }

  def validateApiKey(key: String, requiredScope: Option[String] = None): Option[ApiKey] = {
    apiKeys.get(key).flatMap { apiKey =>
      if (!apiKey.isActive) {
        println(s"[ApiKeyManager] API key is inactive: ${key.take(12)}...")
        None
      } else if (apiKey.expiresAt.exists(Instant.now().isAfter)) {
        println(s"[ApiKeyManager] API key expired: ${key.take(12)}...")
        None
      } else if (requiredScope.exists(!apiKey.scopes.contains(_))) {
        println(s"[ApiKeyManager] API key lacks required scope '${requiredScope.get}': ${key.take(12)}...")
        None
      } else {
        Some(apiKey)
      }
    }
  }

  def authenticateWithSecret(key: String, secret: String): Option[ApiKey] = {
    apiKeys.get(key).filter { apiKey =>
      apiKey.secret == secret && apiKey.isActive &&
        apiKey.expiresAt.forall(Instant.now().isBefore)
    }
  }

  def revokeApiKey(key: String): Boolean = {
    apiKeys.remove(key) match {
      case Some(apiKey) =>
        ownerKeys.updateWith(apiKey.owner) {
          case Some(keys) =>
            val updated = keys - key
            if (updated.isEmpty) None else Some(updated)
          case None => None
        }
        println(s"[ApiKeyManager] Revoked API key: ${key.take(12)}...")
        true
      case None => false
    }
  }

  def revokeAllOwnerKeys(owner: String): Int = {
    val keys = ownerKeys.getOrElse(owner, Set.empty)
    keys.foreach(apiKeys.remove)
    ownerKeys.remove(owner)
    println(s"[ApiKeyManager] Revoked ${keys.size} API keys for owner '$owner'")
    keys.size
  }

  def getOwnerKeys(owner: String): List[ApiKey] = {
    ownerKeys.getOrElse(owner, Set.empty)
      .flatMap(apiKeys.get)
      .filter(_.isActive)
      .toList
  }

  def totalActiveKeys: Int = apiKeys.size
}

class TokenGenerationService(
  sessionDuration: Duration = Duration.ofHours(24),
  maxSessionsPerUser: Int = 5
) {
  private val tokenGenerator = new DefaultTokenGenerator()
  val sessionManager = new SessionManager(tokenGenerator, sessionDuration, maxSessionsPerUser)
  val apiKeyManager = new ApiKeyManager(tokenGenerator)

  def generateCsrfToken(): String = {
    tokenGenerator.generateToken(32)
  }

  def generatePasswordResetToken(): (String, Instant) = {
    val token = tokenGenerator.generateHexToken(32)
    val expiresAt = Instant.now().plus(Duration.ofHours(1))
    (token, expiresAt)
  }

  def generateEmailVerificationToken(): String = {
    tokenGenerator.generateToken(64)
  }

  def generateRefreshToken(): String = {
    tokenGenerator.generateToken(48)
  }

  def stats: Map[String, Int] = Map(
    "activeSessions" -> sessionManager.totalActiveSessions,
    "activeApiKeys" -> apiKeyManager.totalActiveKeys
  )
}

